  1078→// mutates transformations appending a new transformer after the existing one
  1079→function appendTransformerAfter(panel: PanelModel, id: string, cfg: DataTransformerConfig) {
  1080→  if (panel.transformations) {
  1081→    const transformations: DataTransformerConfig[] = [];
  1082→    for (const t of panel.transformations) {
  1083→      transformations.push(t);
  1084→      if (t.id === id) {
  1085→        transformations.push({ ...cfg });
  1086→      }
  1087→    }
  1088→    panel.transformations = transformations;
  1089→  }
  1090→  return panel;
  1091→}
