  1093→function upgradeValueMappingsForPanel(panel: PanelModel) {
  1094→  const fieldConfig = panel.fieldConfig;
  1095→  if (!fieldConfig) {
  1096→    return panel;
  1097→  }
  1098→
  1099→  if (fieldConfig.defaults && fieldConfig.defaults.mappings) {
  1100→    fieldConfig.defaults.mappings = upgradeValueMappings(
  1101→      fieldConfig.defaults.mappings,
  1102→      fieldConfig.defaults.thresholds
  1103→    );
  1104→  }
  1105→
  1106→  // Protect against no overrides
  1107→  if (Array.isArray(fieldConfig.overrides)) {
  1108→    for (const override of fieldConfig.overrides) {
  1109→      for (const prop of override.properties) {
  1110→        if (prop.id === 'mappings') {
  1111→          prop.value = upgradeValueMappings(prop.value);
  1112→        }
  1113→      }
  1114→    }
  1115→  }
  1116→
  1117→  return panel;
  1118→}
