   770→      // Filter out repeats in collapsed rows
   771→      if (panel.type === 'row' && Array.isArray(panel.panels)) {
   772→        panel.panels = panel.panels.filter((x) => !x.repeatPanelId);
   773→      }
   774→
   775→      newPanels.push(panel);
   776→    }
   777→
   778→    this.dashboard.panels = newPanels;
   779→  }
