   796→    }
   797→  }
   798→
   799→  // Migrates CloudWatch annotation queries that use multiple statistics into separate queries.
   800→  // For example, if an annotation query uses ['Max', 'Min'] statistics, it will be split into
   801→  // two separate annotation queries - one with 'Max' and another with 'Min'.
   802→  // The new annotation queries are added to the end of the annotations list.
   803→  migrateCloudWatchAnnotationQuery() {
